"""控制台收件箱 API（公告 + 本地通知）"""from __future__ import annotationsfrom fastapi import APIRouter, Depends, HTTPException, Queryfrom ..models.inbox import (    AnnouncementItem,    InboxListData,    InboxSummary,    NotificationItem,    ReadAllRequest,)from ..services.inbox_service import inbox_servicefrom ..utils.announcements_fetcher import fetch_announcementsfrom ..utils.inbox_notifications import aggregate_notification_rowsfrom ..utils.release_markdown import markdown_to_safe_htmlfrom .deps import get_current_user_flexiblerouter = APIRouter(prefix="/api", tags=["inbox"])async def _fetch_announcement_raw() -> tuple[list[dict], bool, str | None]:    result = await fetch_announcements()    return result.announcements, result.remote_loaded, result.errordef _count_unread_announcements(raw_items: list[dict]) -> int:    read_ids = inbox_service.get_read_announcement_ids()    return sum(1 for raw in raw_items if raw["id"] not in read_ids)def _unread_announcement_ids(raw_items: list[dict]) -> list[str]:    read_ids = inbox_service.get_read_announcement_ids()    return [raw["id"] for raw in raw_items if raw["id"] not in read_ids]def _announcement_item_from_raw(    raw: dict, *, include_body_html: bool, is_read: bool) -> AnnouncementItem:    body_html = ""    if include_body_html:        body_html = markdown_to_safe_html(raw.get("body") or "")    return AnnouncementItem(        id=raw["id"],        title=raw["title"],        level=raw.get("level") or "info",        published_at=raw.get("published_at") or "",        read=is_read,        body_html=body_html,    )async def _load_announcements_list(    unread_only: bool,) -> tuple[list[AnnouncementItem], bool, str | None]:    raw_items, remote_loaded, remote_error = await _fetch_announcement_raw()    read_ids = inbox_service.get_read_announcement_ids()    items: list[AnnouncementItem] = []    for raw in raw_items:        is_read = raw["id"] in read_ids        if unread_only and is_read:            continue        items.append(            _announcement_item_from_raw(raw, include_body_html=False, is_read=is_read)        )    return items, remote_loaded, remote_errorasync def _load_announcement_detail(announcement_id: str) -> AnnouncementItem | None:    raw_items, _remote_loaded, _remote_error = await _fetch_announcement_raw()    read_ids = inbox_service.get_read_announcement_ids()    for raw in raw_items:        if raw["id"] == announcement_id:            return _announcement_item_from_raw(                raw,                include_body_html=True,                is_read=raw["id"] in read_ids,            )    return Nonedef _load_notifications(unread_only: bool, limit: int) -> list[NotificationItem]:    rows = inbox_service.list_in_app_notifications(        limit=limit if unread_only else max(limit, 200),        unread_only=unread_only,    )    aggregated = aggregate_notification_rows(rows)    if limit and len(aggregated) > limit:        aggregated = aggregated[:limit]    return [NotificationItem(**item) for item in aggregated]def _count_aggregated_unread_notifications() -> int:    rows = inbox_service.list_in_app_notifications(unread_only=True, limit=1000)    return len(aggregate_notification_rows(rows))@router.get("/inbox/summary")async def inbox_summary(    current_user: dict = Depends(get_current_user_flexible),):    """未读计数，供铃铛 badge 使用（不渲染公告 Markdown）。"""    _ = current_user    raw_items, _remote_loaded, remote_error = await _fetch_announcement_raw()    ann_count = _count_unread_announcements(raw_items)    notif_count = _count_aggregated_unread_notifications()    return {        "status": "success",        "data": InboxSummary(            announcements=ann_count,            notifications=notif_count,            total=ann_count + notif_count,            remote_error=remote_error,        ).model_dump(),    }@router.get("/inbox")async def inbox_list(    category: str = Query("all"),    unread_only: bool = Query(False),    limit: int = Query(20, ge=1, le=100),    current_user: dict = Depends(get_current_user_flexible),):    """合并收件箱列表。"""    _ = current_user    announcements: list[AnnouncementItem] = []    notifications: list[NotificationItem] = []    remote_loaded = False    remote_error: str | None = None    if category in ("announcement", "all"):        announcements, remote_loaded, remote_error = await _load_announcements_list(            unread_only        )        if limit and len(announcements) > limit:            announcements = announcements[:limit]    if category in ("notification", "all"):        notifications = _load_notifications(unread_only, limit)    return {        "status": "success",        "data": InboxListData(            announcements=announcements,            notifications=notifications,            remote_loaded=remote_loaded,            remote_error=remote_error,        ).model_dump(),    }@router.get("/inbox/announcements/{announcement_id}")async def inbox_announcement_detail(    announcement_id: str,    current_user: dict = Depends(get_current_user_flexible),):    """公告详情（含 Markdown 正文）。"""    _ = current_user    item = await _load_announcement_detail(announcement_id)    if not item:        raise HTTPException(status_code=404, detail="公告不存在")    return {"status": "success", "data": item.model_dump()}@router.post("/inbox/read-all")async def inbox_read_all(    body: ReadAllRequest,    current_user: dict = Depends(get_current_user_flexible),):    """一键已读，可按类别筛选。"""    _ = current_user    category = body.category or "all"    marked = {"announcements": 0, "notifications": 0}    if category in ("announcement", "all"):        raw_items, _, _ = await _fetch_announcement_raw()        marked["announcements"] = inbox_service.mark_all_announcements_read(            _unread_announcement_ids(raw_items)        )    if category in ("notification", "all"):        marked["notifications"] = inbox_service.mark_all_notifications_read()    return {"status": "success", "data": marked}@router.post("/inbox/notifications/{notification_id}/read")async def mark_notification_read(    notification_id: int,    current_user: dict = Depends(get_current_user_flexible),):    _ = current_user    row = inbox_service.get_in_app_notification_by_id(notification_id)    if not row:        raise HTTPException(status_code=404, detail="通知不存在")    if row.get("read_at") is None:        inbox_service.mark_notification_group_read(notification_id)    return {"status": "success", "data": {"id": notification_id, "read": True}}@router.post("/inbox/announcements/{announcement_id}/read")async def mark_announcement_read(    announcement_id: str,    current_user: dict = Depends(get_current_user_flexible),):    _ = current_user    inbox_service.mark_announcement_read(announcement_id)    return {        "status": "success",        "data": {"id": announcement_id, "read": True},    }